export const GetDashboardSummaryResponse = zod.object({
  totalJobs: zod.number(),
  activeJobs: zod.number(),
  totalApplicants: zod.number(),
  newApplicantsThisWeek: zod.number(),
  interviewsThisWeek: zod.number(),
  interviewsCompleted: zod.number(),
  avgInterviewScore: zod.number().nullish(),
  hiresThisMonth: zod.number(),
});

/**
 * @summary Get recent activity feed
 */
export const getRecentActivityQueryLimitDefault = 10;

export const GetRecentActivityQueryParams = zod.object({
  limit: zod.coerce.number().default(getRecentActivityQueryLimitDefault),
});

export const GetRecentActivityResponseItem = zod.object({
  id: zod.string(),
  type: zod.enum([
    "new_applicant",
    "interview_scheduled",
    "interview_completed",
    "applicant_hired",
    "applicant_rejected",
    "job_posted",
  ]),
  title: zod.string(),
  description: zod.string(),
  timestamp: zod.coerce.date(),
  metadata: zod.object({}).passthrough().nullish(),
});
export const GetRecentActivityResponse = zod.array(
  GetRecentActivityResponseItem,
);

/**
 * @summary Get applicant pipeline breakdown by stage
 */
export const GetPipelineStatsResponse = zod.object({
  stages: zod.array(
    zod.object({
      stage: zod.string(),
      count: zod.number(),
      percentage: zod.number(),
    }),
  ),
  byJob: zod.array(
    zod.object({
      jobId: zod.number(),
      jobTitle: zod.string(),
      count: zod.number(),
    }),
  ),
});
